class MyModule(ForgeModule):
    name = 'my_module'
    dependencies = ['config', 'log']

    async def setup(self, runtime):
        self.config = runtime.get_config()

    async def teardown(self):
        pass

    def health_check(self) -> HealthResult:
        return HealthResult.ok()

